import*as Schema from"../schema.js";import*as Instance from"../instance.js";const id="https://json-schema.org/keyword/multipleOf",compile=e=>Schema.value(e),interpret=(e,t)=>{if(!Instance.typeOf(t,"number"))return!0;t=Instance.value(t)%e;return numberEqual(0,t)||numberEqual(e,t)},numberEqual=(e,t)=>Math.abs(e-t)<1.1920929e-7;export default{id:id,compile:compile,interpret:interpret};